final:
module ALU (  
    input [31:0] obf_A,  
    input [31:0] B,  
    input [3:0] opcode,  
    output reg [31:0] result,  
    output reg ZF  
);  
    always @(*) begin  
        case (opcode)  
            4'b0000: result = obf_A + B;  
            4'b0001: result = obf_A - B;  
            4'b0010: result = obf_A & B;  
            4'b0011: result = obf_A | B;  
            4'b0100: result = obf_A ^ B;  
            4'b0101: result = ~(obf_A | B);  
            4'b0110: result = ~(obf_A & B);  
            4'b0111: result = ~(obf_A ^ B);  
            default: result = 32'b0;  
        endcase  
        ZF = (result == 32'b0);  
    end  
endmodule
